// Load-shed priority: shed by L1/L2 when power is short
function shedLoad(P_now, P_L2, P_L1) {
  if (P_now >= P_L2) return 'all_loads';
  if (P_now >= P_L1) return 'shed_noncritical';  // science, lighting, etc.
  return 'life_support_only';  // life support + comms only, alert RTG standby
}

graph TD
    P[Current power] --> C{Enough?}
    C -->|Yes| N[All loads]
    C -->|No| T{Below L2?}
    T -->|Yes| S[Shed noncritical]
    T -->|No| R{Below L1?}
    R -->|Yes| M[Life support + comms only]
    R -->|No| E[Alert + RTG takeover]
    S --> N
    style E fill:#b91c1c33
